import re
from abc import ABCMeta, abstractmethod
from typing import Iterator, Mapping, Optional, Pattern

_posix_variable: Pattern[str] = re.compile(
    r"""
    \$\{
        (?P<name>[^\}:]*)
        (?::-
            (?P<default>[^\}]*)
        )?
    \}
    """,
    re.VERBOSE,
)


class Atom(metaclass=ABCMeta):
    def __ne__(self, other: object) -> bool:
        """Return the inverse of __eq__ or NotImplemented when appropriate."""
        result = self.__eq__(other)
        if result is NotImplemented:
            return NotImplemented
        return not result

    @abstractmethod
    def resolve(self, env: Mapping[str, Optional[str]]) -> str:
        """Resolve this atom against the provided environment mapping.

        Implementations should return the resolved string value. The environment
        maps variable names to optional string values (None indicates absence).
        """
        raise NotImplementedError


class Literal(Atom):
    def __init__(self, value: str) -> None:
        """Create a Literal atom holding the given string value."""
        self.value = value

    def __repr__(self) -> str:
        """Return a representation useful for debugging."""
        return f"Literal(value={self.value})"

    def __eq__(self, other: object) -> bool:
        """Return True if other is a Literal with the same value."""
        if not isinstance(other, self.__class__):
            return NotImplemented
        return self.value == other.value

    def __hash__(self) -> int:
        """Return a hash combining the class and the stored value."""
        return hash((self.__class__, self.value))

    def resolve(self, env: Mapping[str, Optional[str]]) -> str:
        """Resolve this literal (returns its value unchanged)."""
        return self.value


class Variable(Atom):
    def __init__(self, name: str, default: Optional[str]) -> None:
        """Create a Variable atom with a name and an optional default."""
        self.name = name
        self.default = default

    def __repr__(self) -> str:
        """Return a representation useful for debugging."""
        return f"Variable(name={self.name}, default={self.default})"

    def __eq__(self, other: object) -> bool:
        """Return True if other is a Variable with the same name and default."""
        if not isinstance(other, self.__class__):
            return NotImplemented
        return (self.name, self.default) == (other.name, other.default)

    def __hash__(self) -> int:
        """Return a hash combining the class, name, and default."""
        return hash((self.__class__, self.name, self.default))

    def resolve(self, env: Mapping[str, Optional[str]]) -> str:
        """Resolve this variable using the environment mapping and default.

        If the variable is missing from env, the default is used. If either the
        default or the looked-up value is None, an empty string is returned.
        """
        default = self.default if self.default is not None else ""
        result = env.get(self.name, default)
        return result if result is not None else ""


def parse_variables(value: str) -> Iterator[Atom]:
    """Parse a string yielding Literal and Variable atoms for POSIX-style ${...}.

    Yields Literal objects for text outside variable expressions and Variable
    objects for expressions of the form ${name:-default}.
    """
    cursor = 0

    for match in _posix_variable.finditer(value):
        (start, end) = match.span()
        name = match["name"]
        default = match["default"]

        if start > cursor:
            yield Literal(value=value[cursor:start])

        yield Variable(name=name, default=default)
        cursor = end

    length = len(value)
    if cursor < length:
        yield Literal(value=value[cursor:length])